// ============================================================
// Kontakte aus Excel mappen + Testmodus (5 Kontakte)
// ============================================================
const allItems = items.map(i => i.json);

const leadtypValue = $('Upload Formular').first().json['Leadtyp'] || 'Unternehmerboard';
const listId       = $('Upload Formular').first().json['HubSpot Listen-ID'] || '';
const testmodus    = ($('Upload Formular').first().json['Testmodus (nur erste 5 Kontakte)'] || 'Nein') === 'Ja';

const VALID_BRANCHEN = ['Werbung/Design','Coaching','Personal','Health','Logistik','B2B Services','Handwerk','Elektrontechnik','Immobilien','Maschinenbau','Handel','Chemie','Consulting','Bau','Architektur-Design','Software','Produktion'];
const BRANCHEN_ALIASES = {
  'elektrotechnik':'Elektrontechnik','elektro':'Elektrontechnik',
  'it':'Software','informatik':'Software',
  'architektur':'Architektur-Design','werbung':'Werbung/Design','design':'Werbung/Design',
  'hr':'Personal','gesundheit':'Health','transport':'Logistik','dienstleistungen':'B2B Services',
};
function mapBranchen(raw) {
  const v = (raw||'').toString().trim();
  if (!v) return '';
  if (VALID_BRANCHEN.includes(v)) return v;
  const lower = v.toLowerCase();
  return VALID_BRANCHEN.find(b=>b.toLowerCase()===lower) || BRANCHEN_ALIASES[lower] || '';
}

const VALID_EMPLOYEES = ['1-5','5-25','25-50','50-100','100-500','500-1000','1000+'];
function mapNumEmployees(raw) {
  const v = (raw||'').toString().trim();
  if (!v) return '';
  if (VALID_EMPLOYEES.includes(v)) return v;
  const match = v.match(/(\d+)/);
  if (!match) return '';
  const n = parseInt(match[1],10);
  if (n<=5) return '1-5'; if (n<=25) return '5-25'; if (n<=50) return '25-50';
  if (n<=100) return '50-100'; if (n<=500) return '100-500'; if (n<=1000) return '500-1000';
  return '1000+';
}

const result = [];
for (const row of allItems) {
  const email = (row['email']||'').toString().trim();
  if (!email) continue;

  let phone = (row['phone']||'').toString().trim();
  if (phone.startsWith("'")) phone = phone.slice(1);

  const branchenVal     = mapBranchen(row['industry']);
  const numemployeesVal = mapNumEmployees(row['companySize']);

  const mapped = {
    email,
    firstname:       (row['firstName']    ||'').toString().trim(),
    lastname:        (row['lastName']     ||'').toString().trim(),
    phone,
    hs_linkedin_url: (row['linkedinUrl']  ||'').toString().trim(),
    jobtitle:        (row['jobTitle']     ||'').toString().trim(),
    company:         (row['companyName']  ||'').toString().trim(),
    website:         (row['companyWebsite']||row['website']||row['companyDomain']||'').toString().trim(),
    leadtyp:         leadtypValue,
    _listId:         listId,
  };
  if (branchenVal)     mapped.branchen     = branchenVal;
  if (numemployeesVal) mapped.numemployees = numemployeesVal;

  result.push({ json: mapped });
  if (testmodus && result.length >= 5) break;
}

return result;

// Extrahiert alle HubSpot-IDs und bereitet den Segment-Add vor.
// Ein einziger API-Call fügt alle Kontakte gleichzeitig hinzu.
const allData = items[0].json.data || [];
const listId  = $('Upload Formular').first().json['HubSpot Listen-ID'] || '';

if (!allData.length) {
  throw new Error('Keine Kontakte vom Upsert zurückgegeben. Prüfe den HubSpot Kontakt Upsert Node.');
}

// Alle bekannten ID-Felder des HubSpot v2 Node-Outputs durchprobieren
const ids = [];
for (const row of allData) {
  const id = (row['hs_object_id'] || row['vid'] || '').toString().trim();
  if (id) ids.push(id);
}

if (!ids.length) {
  // Debug: Zeige welche Felder verfügbar sind
  const sampleKeys = Object.keys(allData[0] || {}).slice(0, 30).join(', ');
  throw new Error(
    'Keine HubSpot-ID in Upsert-Output gefunden.' +
    ' Kontaktanzahl: ' + allData.length +
    '. Verfügbare Felder: ' + sampleKeys
  );
}

return [{ json: { listId, contactIds: ids, count: ids.length } }];

// CSV mit email + hubspotId für Rückschreiben in die Quelldatei
const allData = $('Alle IDs sammeln').first().json.data || [];

let csvLines = ['email,hubspotId'];
for (const row of allData) {
  const email = (row.email || '').replace(/,/g, '');
  const hsId  = (row.hs_object_id || row.vid || row.id || '').toString();
  csvLines.push(`${email},${hsId}`);
}

return [{
  json: {
    totalImported: csvLines.length - 1,
    message: `${csvLines.length - 1} Kontakte importiert und Segment hinzugefügt`,
  },
  binary: {
    data: {
      data: Buffer.from(csvLines.join('\n')).toString('base64'),
      mimeType: 'text/csv',
      fileExtension: 'csv',
      fileName: 'hubspot_ids_rueckschreiben.csv',
    }
  }
}];
